scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + new Date(scwin.vCurDate.substring(0, 4), scwin.vCurDate.substring(4, 6) , 0).getDate();;  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)

scwin.districtCd = "";
scwin.curRow = 0;

scwin.onpageload = function() {
    const codeOptions = [
        { grpCd : "OP256", compID : "lc_morningEarlySalStd,lc_saturdayMorningEarlySalStd,lc_basisSalStd,lc_saturdayBasisSalStd,lc_nightEarlySalStd,lc_saturdayNightEarlySalStd,lc_extdSalStd,lc_saturdayExtdSalStd,lc_midngtSalStd,lc_saturdayMidngtSalStd,lc_ecsSalStd,lc_saturdayEcsSalStd" },

    ];
    $c.data.setCommonCode(codeOptions);

    const codeOptions2 = [ 
        {
            method: "getLuxeComboData", 
            param1: "GoodsSurchargeWorkStepEBC", 
            param2: "retriveDistrictCodeListForIncheon",
            //param3: ["CMP"],
            compID: "lc_con_districtCd" 
        }
    ];
    $c.data.setGauceUtil(codeOptions2, scwin.callbackCode2);

    //lc_con_districtCd.setSelectedIndex(0);

    let memJson = $c.data.getMemInfo();
    console.log(memJson);
    scwin.districtCd = memJson.districtCd;

    $c.gus.cfDisableObjects([btn_Add,btn_Update,btn_Save,con_main,table1]);

    scwin.f_init();
};

scwin.callbackCode2 = function () {
    $p.setTimeout(function() {
        lc_con_districtCd.setSelectedIndex(0);
    }, {"delay":100});
}

scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
		scwin.f_FieldClear();
        ///임시
        ///임시
        //scwin.f_setDataSetList();


    }, {"delay":50});
};

scwin.f_init = function () {

