    lc_saturdayMorningEarlyStHh.setSelectedIndex(0);
    lc_saturdayMorningEarlyEndHh.setSelectedIndex(0);
    lc_saturdayMorningEarlySalStd.setSelectedIndex(4);

    lc_workStHh.setSelectedIndex(0);
    lc_workEndHh.setSelectedIndex(0);
    lc_basisSalStd.setSelectedIndex(4);
    lc_saturdayWorkStHh.setSelectedIndex(0);
    lc_saturdayWorkEndHh.setSelectedIndex(0);
    lc_saturdayBasisSalStd.setSelectedIndex(4);

    lc_nightEarlyStHh.setSelectedIndex(0);
    lc_nightEarlyEndHh.setSelectedIndex(0);
    lc_nightEarlySalStd.setSelectedIndex(4);
    lc_saturdayNightEarlyStHh.setSelectedIndex(0);
    lc_saturdayNightEarlyEndHh.setSelectedIndex(0);
    lc_saturdayNightEarlySalStd.setSelectedIndex(4);

    lc_extdStHh.setSelectedIndex(0);
