//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    var chk =  await $c.gus.cfValidate([tb_condition]);
    if(!chk) return;

    /// 임시
    //dma_oGDS_view_cond.set("districtCd","IHP");
    /// 임시

    $c.sbm.execute(sbm_retrieve);
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function (){

    scwin.curRow = ds_retrieveResult.getRowPosition();
    var chk = await $c.gus.cfValidate([main_table]);

    if(!scwin.f_basicMoney()) return;
    if(!chk) return;

    if(!scwin.f_checkDate())  return;
    if(!scwin.f_checkTime())  return;


    if( ds_retrieveResult.getModifiedIndex().length == 0 ){
        $c.win.alert("변경된 사항이 없습니다.");
    }else if(await $c.win.confirm(MSG_CM_CRM_001)){
        $c.sbm.execute(sbm_save);
    }
}

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = function () {
}

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Modify = function () {
    $c.gus.cfEnableObjects([con_main, table1]);
    $c.gus.cfEnableBtnOnly([btn_Add, btn_Save]);
    //cfDisableObjects([lc_morningEarlySalStd, lc_saturdayMorningEarlySalStd,lc_basisSalStd,lc_saturdayBasisSalStd,lc_nightEarlySalStd, lc_saturdayNightEarlySalStd,lc_extdSalStd,lc_saturdayExtdSalStd,lc_midngtSalStd,lc_saturdayMidngtSalStd,lc_ecsSalStd,lc_saturdayEcsSalStd]);
    $c.gus.cfDisableObjects([ica_adptStDt, ica_wageAgrmntDt]);
}

scwin.f_OnLoadCompleted = function (rowcnt) {
    if (rowcnt > 0) {
        $c.gus.cfEnableObjects([btn_Update, btn_Save]);
    }
}

//-------------------------------------------------------------------------
// 조회 조건 초기화
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    ica_con_wageAgrmntDt.setValue("");
    ica_con_adptDt.setValue("");
    var districtCd = scwin.districtCd;

    if(districtCd == "" || districtCd == null) {
        lc_con_districtCd.setSelectedIndex(-1);
    } else {
        alert("!!");
        lc_con_districtCd.setValue(districtCd);
    }
}

scwin.f_basicMoney = function () {
    var value = ed_pyDdBasisAmt.getValue();
    if ( value == "0" || value == "" ) {
        $c.win.alert("평일기본금액은 필수 입력 항목입니다.");
        ed_pyDdBasisAmt.focus();
        return false;
    }

    return true;
}

scwin.f_checkDate = function () {

    var adptStDt  = ds_retrieveResult.getCellData(ds_retrieveResult.getRowCount(),"adptStDt");
    var adptEndDt = ds_retrieveResult.getCellData(ds_retrieveResult.getRowCount(),"adptEndDt");

    if ( adptEndDt != "99999999" ) {
        var chk = $c.gus.cfIsAfterDate(adptStDt, adptEndDt, false)
        if (!chk) {
            $c.win.alert("적용종료일을 적용시작일보다 이후로 입력하십시오.");
            ds_retrieveResult.setCellData(row,"adptEndDt","99999999");
            return false;
        }
    }
    return true;
}

scwin.f_checkTime = async function () {

    var row       = ds_retrieveResult.getRowCount();
    var adptStDt  = ds_retrieveResult.getCellData(ds_retrieveResult.getRowCount(),"adptStDt");


    for (var i=0; i < row; i++) {

        var workStHh             = adptStDt+ds_retrieveResult.getCellData(i,"workStHh"            )+"00";   //근무시작시간
        var workEndHh            = adptStDt+ds_retrieveResult.getCellData(i,"workEndHh"           )+"00";   //근무종료시간
        var saturdayWorkStHh     = adptStDt+ds_retrieveResult.getCellData(i,"saturdayWorkStHh"    )+"00";   //토요일근무시작시간
        var saturdayWorkEndHh    = adptStDt+ds_retrieveResult.getCellData(i,"saturdayWorkEndHh"   )+"00";   //토요일근무종료시간

        var extdStHh             = adptStDt+ds_retrieveResult.getCellData(i,"extdStHh"            )+"00";   //연장시작시간
        var extdEndHh            = adptStDt+ds_retrieveResult.getCellData(i,"extdEndHh"           )+"00";   //연장종료시간
        var saturdayExtdStHh     = adptStDt+ds_retrieveResult.getCellData(i,"saturdayExtdStHh"    )+"00";   //토요일연장시작시간
        var saturdayExtdEndHh    = adptStDt+ds_retrieveResult.getCellData(i,"saturdayExtdEndHh"   )+"00";   //토요일연장종료시간

        var midngtStHh           = adptStDt+ds_retrieveResult.getCellData(i,"midngtStHh"          )+"00";   //심야시작시간
        var midngtEndHh          = adptStDt+ds_retrieveResult.getCellData(i,"midngtEndHh"         )+"00";   //심야종료시간
        var saturdayMidngtStHh   = adptStDt+ds_retrieveResult.getCellData(i,"saturdayMidngtStHh"  )+"00";   //토요일심야시작시간
        var saturdayMidngtEndHh  = adptStDt+ds_retrieveResult.getCellData(i,"saturdayMidngtEndHh" )+"00";   //토요일심야종료시간

        var chk1 = await $c.gus.cfIsAfterTime(workStHh, workEndHh, false, i);
        if (!chk1) {
            $c.win.alert(i+"번째 Row의 근무종료시간을 근무시작시간 이후로 선택하십이오.");
            lc_workEndHh.focus();
            return false;
        }

        var chk2 = await $c.gus.cfIsAfterTime(saturdayWorkStHh, saturdayWorkEndHh, false, i);
        if (!chk2) {
            $c.win.alert(i+"번째 Row의 토요일근무종료시간을 토요일근무시작시간 이후로 선택하십이오.");
            lc_saturdayWorkEndHh.focus();
            return false;
        }

    }
    return true;
}

scwin.cfIsAfterTime = function (startDate, endDate, exceptSameDate, i) {
    var sDate = startDate.toDate("YYYYMMDDHHMI");
    var eDate = endDate.toDate("YYYYMMDDHHMI");

    if (exceptSameDate != null && exceptSameDate == true) {
        if (sDate < eDate)
            return true;
        else
            ds_retrieveResult.setRowPosition(i);
            return false;

    } else {
        if (sDate <= eDate)
            return true;
        else
            ds_retrieveResult.setRowPosition(i);
            return false;
    }
}

scwin.f_RowChange = function () {

    var rowstatus = ds_retrieveResult.getRowStatus(ds_retrieveResult.getRowPosition());
    var value = ds_retrieveResult.getCellData(ds_retrieveResult.getRowPosition(), "adptEndDt");

    if ( value != "99999999" ) {
        $c.gus.cfDisableObjects([btn_Update]);
        //btn_Update.setDisabled(true);
    }
    else if ( value == "99999999" ) {
        $c.gus.cfEnableObjects([btn_Update]);
    }

    if ( rowstatus == "R" ) {
        $c.gus.cfDisableObjects([con_main, table1]);    
        $c.gus.cfDisableObjects([ica_adptStDt, ica_wageAgrmntDt]);
    } else if ( rowstatus != "R" ) {
        $c.gus.cfEnableObjects([con_main, table1]);
        //cfDisableObjects([lc_basisSalStd,lc_saturdayBasisSalStd,lc_extdSalStd,lc_saturdayExtdSalStd,lc_midngtSalStd,lc_saturdayMidngtSalStd]);
    }
}

scwin.f_checkEndDate = function () {
    var row = ds_retrieveResult.getRowCount();

    for(i=0; i < row; i++) {
        var value = ds_retrieveResult.getCellData(i, "adptEndDt");
        if ( value == "99999999" ) {
            $c.win.alert((i+1)+"번째 적용종료 처리되지 않은 근무기준이 존재합니다.");
            return false;
        }
    }
    return true;
}


