scwin.btn_search_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_Add_onclick = function (e) {
    scwin.f_AddRow();
};

scwin.btn_Update_onclick = function (e) {
    scwin.f_Modify();
};

scwin.btn_Save_onclick = function (e) {
    scwin.f_Save();
};

scwin.gr_retrieveResult_onrowindexchange = function (rowIndex, oldRow) {
    scwin.f_RowChange();
};

/////////////////////////////////////////////////////////
//////////////// OBJECT EVENT END  //////////////////////
/////////////////////////////////////////////////////////

/////////////////////////////////////////////////////////
//////////////// Submission EVENT START  ////////////////
/////////////////////////////////////////////////////////

scwin.sbm_retrieve_submitdone = function (e) {

    $c.gus.cfEnableObjects([btn_Add]);

    scwin.curRow = ds_retrieveResult.getRowCount();
    ds_retrieveResult.setRowPosition(scwin.curRow-1);
    gr_retrieveResult.setFocusedCell(scwin.curRow-1, 0);


    var rowcnt = ds_retrieveResult.getRowCount();
    scwin.f_OnLoadCompleted(rowcnt);

    if ( rowcnt == 0 ) {
        $c.win.alert(MSG_CM_WRN_002);
    }

    scwin.f_RowChange();
};

scwin.sbm_save_submitdone = function (e) {
    $c.gus.cfEnableBtnOnly([btn_Add, btn_Update]);

    //rowFlag = "";  // 초기화
    $c.win.alert(MSG_CM_INF_001); // 성공적으로 저장하였습니다.

    scwin.f_Retrieve();
};

/////////////////////////////////////////////////////////
//////////////// Submission EVENT END  //////////////////
/////////////////////////////////////////////////////////

scwin.ds_retrieveResult_ondataload = function () {
    spa_cnt.setValue(ds_retrieveResult.getRowCount());
};
